import boto3, json

# Grant S3 permission to invoke a Lambda function (resource-based policy on Lambda)
lambda_client = boto3.client('lambda')
lambda_client.add_permission(
    FunctionName='process-uploads',
    StatementId='s3-invoke-permission',
    Action='lambda:InvokeFunction',
    Principal='s3.amazonaws.com',
    SourceArn='arn:aws:s3:::my-upload-bucket',
    SourceAccount='123456789012'  # prevents confused deputy attacks
)

# Configure S3 to send event notifications to Lambda
s3 = boto3.client('s3')
s3.put_bucket_notification_configuration(
    Bucket='my-upload-bucket',
    NotificationConfiguration={
        'LambdaFunctionConfigurations': [{
            'LambdaFunctionArn': 'arn:aws:lambda:us-east-1:123456789012:function:process-uploads',
            'Events': ['s3:ObjectCreated:*'],
            'Filter': {
                'Key': {
                    'FilterRules': [
                        {'Name': 'prefix', 'Value': 'uploads/'},
                        {'Name': 'suffix', 'Value': '.csv'}
                    ]
                }
            }
        }]
    }
)

